import 'package:flutter_secure_storage/flutter_secure_storage.dart';

final LocalAuthentication _localAuthentication = LocalAuthentication();
final Storage _secureStorage = FlutterSecureStorage();
SharedPreferences _prefs;

Future<void> checkBiometrics() async {
  bool canCheck Bio = await _localAuthentication.canCheckBiometrics;
  if (canCheckBio) {
    List<BiometricType> availableBiometrics =
        await _localAuthentication.getAvailableBiometrics();

    if (availableBiometrics.contains(BiometricType.faceId)) {
      _authenticateWithFaceId();
    } else if (availableBiometrics.contains(BiometricType.fingerprint)) {
      _authenticateWithFingerprint();
    } else {
      print('No biometric available');
      Navigator.pushReplacementNamed(context, '/login'); // Navigate to login screen
    }
  } else {
    print('Device does not support biometrics');
    Navigator.pushReplacementNamed(context, '/login'); // Navigate to login screen
  }
}

Future<void> _authenticateWithFingerprint() async {
  bool authenticated = false;

  try {
    authenticated = await _localAuthentication.authenticateWithBiometrics(
      localizedReason: 'Authenticate with fingerprint to access your account',
      useBiometricPrompt: true,
      biometricTypes: BiometricType.fingerprint,
      cancelLabel: 'Cancel',
      fallbackLabel: 'Use Password',
    );

    if (authenticated) {
      _storeAuthenticationStatus(true);
      Navigator.pushReplacementNamed(context, '/main'); // Navigate to main screen
    }
  } catch (e) {
    print('Error during authentication: $e');
  }
}

